import React from 'react';
import { BrowserRouter as Router, Route, Routes, Link } from 'react-router-dom';
import './App.css';

import Clothing from './components/Clothing/Clothing';
import MensClothing from './components/Clothing/MensClothing';
import WomensClothing from './components/Clothing/WomensClothing';
import KidsClothing from './components/Clothing/KidsClothing';
import Footwear from './components/Footwear/Footwear';
import MenFootwear from './components/Footwear/MenFootwear';
import WomenFootwear from './components/Footwear/WomenFootwear';
import KidFootwear from './components/Footwear/KidFootwear';
import Gear from './components/Gear/Gear';
import SleepSystem from './components/Gear/SleepSystem';
import Packs from './components/Gear/Packs';
import Tents from './components/Gear/Tents';
import Accessories from './components/Accessories/Accessories';
import Contact from './components/Static/Contact';
import About from './components/Static/About';
import PrivacyPolicy from './components/Static/PrivacyPolicy';
import Footer from './components/Footer';
import Cart from './Cart';
import CampKitchen from './components/Gear/CampKitchen';
import { CartProvider } from './components/Context/CartContext';
import { UserAuthProvider } from './components/Context/UserAuth';
import SignIn from './SignIn';
import SignUP from './SignUP';
import SupplierDashboard from './components/Dashboards/SupplierDashboard';
import UserDashboard from './components/Dashboards/UserDashboard';
import AdditionalGear from './components/Gear/AdditionalGear';
import AdminDashboard from './components/Dashboards/AdminDashboard';
import ClothingAccess from './components/Accessories/ClothingAccess';
import FootwearAccess from './components/Accessories/FootwearAccess';
import BagpackAccess from './components/Accessories/BagpackAccess';
import ProtectedSupplierDashboard from './SupplierProtectedRoute';
import { AdminRoute } from './ProtectedRoute';
import Header from './components/Header';
import NavBar from './components/NavBar';
import Home from './Home';
import Checkout from './Checkout';
 
function App() {
  return (
    <UserAuthProvider>
      <CartProvider>
        <Router>
          <div className="App">
            <Header/>
            <NavBar/>  {/* This is your NavBar component. Keep this only once */}

            <main>
              <Routes>
                <Route path="/" element={<Home />} />
                <Route path="/clothing" element={<Clothing />} />
                <Route path="/clothing/men" element={<MensClothing />} />
                <Route path="/clothing/women" element={<WomensClothing />} />
                <Route path="/clothing/kids" element={<KidsClothing />} />
                <Route path="/footwear" element={<Footwear />} />
                <Route path="/footwear/men" element={<MenFootwear />} />
                <Route path="/footwear/women" element={<WomenFootwear />} />
                <Route path="/footwear/kids" element={<KidFootwear />} />
                <Route path="/gear" element={<Gear />} />
                <Route path="/accessories" element={<Accessories />} />
                <Route path="/accessories/backpack" element={<BagpackAccess />} />
                <Route path="/accessories/clothing" element={<ClothingAccess />} />
                <Route path="/accessories/footwear" element={<FootwearAccess />} />

                <Route path="/checkout" element={<Checkout />} />
                <Route path="/contact" element={<Contact />} />
                <Route path="/about" element={<About />} />
                <Route path="/privacy-policy" element={<PrivacyPolicy />} />
                <Route path="/cart" element={<Cart />} />
                <Route path="/signin" element={<SignIn />} />
                <Route path="/signup" element={<SignUP />} />

                {/* Admin can access these routes */}
                <Route path="/gear/sleep" element={<SleepSystem />} />
                <Route path="/gear/kitchen" element={<CampKitchen />} />
                <Route path="/gear/packs" element={<Packs />} />
                <Route path="/gear/tents" element={<Tents />} />
                <Route path="/gear/additional" element={<AdditionalGear />} />
                {/* Protected routes for admin */}
                <Route path="/admin" element={<AdminRoute><AdminDashboard /></AdminRoute>} />
                {/* Routes restricted for admin */}
                <Route path="/user-dashboard" element={<UserDashboard />} />
                <Route path="/supplier-dashboard" element={<ProtectedSupplierDashboard><SupplierDashboard /></ProtectedSupplierDashboard>} />
              </Routes>
            </main>

            <Footer />
          </div>
        </Router>
      </CartProvider>
    </UserAuthProvider>
  );
}

export default App;
